"""check-prompt-injection.py — Flag unguarded user input interpolation in prompt files."""
import ast, sys, re
from pathlib import Path

# Patterns that suggest user input may be interpolated directly into a prompt
INJECTION_PATTERNS = [
    (r'f".*\{user_', "f-string with user_ variable in prompt"),
    (r'f".*\{request\.', "f-string with request attribute in prompt"),
    (r'\.format\(.*user_input', ".format() with user_input in prompt"),
    (r'%s.*%.*user', "%-format with user variable in prompt"),
    (r'\+\s*user_input', "String concatenation with user_input"),
]

def check_file(path: Path) -> list[dict]:
    findings = []
    content = path.read_text()
    for pattern, description in INJECTION_PATTERNS:
        for i, line in enumerate(content.splitlines(), 1):
            if re.search(pattern, line, re.IGNORECASE):
                findings.append({
                    "file": str(path),
                    "line": i,
                    "finding": description,
                    "code": line.strip(),
                })
    return findings

def main(prompt_dir: str) -> int:
    all_findings = []
    for path in Path(prompt_dir).rglob("*.py"):
        all_findings.extend(check_file(path))
    for path in Path(prompt_dir).rglob("*.txt"):
        # Also check template files
        content = path.read_text()
        if '{user_input}' in content or '{user_message}' in content:
            # Jinja2-style templates in prompt files need validation audit
            all_findings.append({
                "file": str(path),
                "line": 0,
                "finding": "Template variable in prompt file — verify sanitization in caller",
                "code": "",
            })
    if all_findings:
        print("PROMPT INJECTION SURFACE FINDINGS:")
        for f in all_findings:
            print(f"  {f['file']}:{f['line']} — {f['finding']}")
            if f['code']:
                print(f"    {f['code']}")
        print(f"\n{len(all_findings)} finding(s). Review and sanitize before merging.")
        return 1
    print("No prompt injection surfaces found.")
    return 0

if __name__ == "__main__":
    sys.exit(main(sys.argv[1] if len(sys.argv) > 1 else "src/prompts"))
